image:
{{
  (() => {
    // 1. Get the current active record from our manager
    const active = PreviewManager.getActiveData();

    // 2. Safety: If no recipe or no picture file, show a placeholder
    if (!active || !active.Picture) {
      return "https://placehold.co/600x400?text=Awaiting+Schematic";
    }

    // 3. Construct the PocketBase URL
    const macIp = "192.168.10.63"; 
    const collection = "Schematics"; 

    // Pattern: http://IP:PORT/api/files/COLLECTION/ID/FILENAME
    return `http://${macIp}:8090/api/files/${collection}/${active.id}/${active.Picture}`;
  })()
}}
